  ('elementary-e0adf6cd-moex-00964', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '依據國民小學與國民中學未入學或中途輟學學生通報及復學輔導辦法規定，直轄市、縣（市）政府對中 輟生復學後不適應一般學校教育課程者，透過鄰近學區教學資源共享方式，遴選轄內國民中小學分區設 置，以提供適性教育課程，避免學生再度輟學之班別為下列何者？', '["慈輝班", "高關懷班", "資源式中途班", "合作式中途班"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00965', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '有關學校訂定教師輔導與管教學生辦法注意事項之規定，下列何者錯誤？', '["學生對於教師之處罰措施提出異議，教師應調整或停止所執行之處罰措施", "經學生獎懲委員會議決學生交由監護人帶回管教，每次以5日為限", "除有特殊情形外，教師不得於學生下課時間實施第22條所列一般管教措施", "教師得暫時讓學生在教學場所一隅，與其他同學保持適當距離，但以一堂課為限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00966', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '依據教育經費編列與管理法之規定，教育部教育經費分配審議委員會之學者、專家、社會公正人士委員 人數，合計不得少於委員總數之多少？', '["二分之一", "三分之一", "四分之一", "無限制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00967', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '依據高級中等教育法之規定，教育部為審查課程綱要應設課程審議會，並由政府機關代表及非政府機關 代表組成。政府機關代表及非政府機關代表中，均應包含具下列何種身分者？', '["原住民", "身心障礙者", "具外國大學以上學歷者", "性別平等教育相關專家學者或民間團體代表"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
